import type moment from 'moment';
import React from 'react';
import type { MODE } from '../../interface';
import DateBody from '../date-body';
import MonthBody from '../month-body';
import YearBody from '../year-body';

const MODE_BODY = {
  date: DateBody,
  month: MonthBody,
  year: YearBody,
} as const;

export interface PickerBodyProps {
  /**
   * 日期面板的状态，可选年、月、日
   */
  mode: MODE;

  /**
   * 自定义日期选项渲染
   */
  dateRender?: (currentDate: moment.Moment, mode?: MODE, defaultNode?: React.ReactNode) => React.ReactNode;
}

function PickerBody(props: PickerBodyProps) {
  const { mode } = props;
  const Body = MODE_BODY[mode];

  return <Body />;
}

export default PickerBody;
